import { Routes } from '@angular/router';
import { authGuard } from './core/guards/auth.guard';
import { FlowRoute } from './flow-meta';

// `data.flow` is the single source of truth for the user-flow graph AND the runtime navbar.
// The colossus flow-graph extractor projects it directly (zero heuristics). Authoring rules
// + lint: docs/flow-graph-convention.md + platform/flowgraph-static/verify/flow-lint.mjs.
//
// DEEP-LINKABLE STATE — the editor shell (`workspaces/:id`) exposes every navigable state via
// query params so automated verification can land on it:
//   • ?open=<nodeId>                 → active file tab (restored on load)
//   • ?panel=search&q=<term>         → search drawer with results
//   • ?modal=revisions&node=<nodeId> → revision-history dialog
//   • ?modal=new                     → create file/folder dialog
export const routes: Routes = ([
  { path: '', redirectTo: 'workspaces', pathMatch: 'full' },
  {
    path: 'login',
    loadComponent: () =>
      import('./features/login/login.component').then((m) => m.LoginComponent),
    data: { flow: { flowId: 'login', node: 'login', entry: true, edgesTo: ['signup', 'workspaces'], label: 'Login' } },
  },
  {
    path: 'signup',
    loadComponent: () =>
      import('./features/signup/signup.component').then((m) => m.SignupComponent),
    data: { flow: { flowId: 'signup', node: 'signup', edgesTo: ['login', 'workspaces'], label: 'Sign up' } },
  },
  {
    path: 'workspaces',
    loadComponent: () =>
      import('./features/workspaces/workspace-list.component').then((m) => m.WorkspaceListComponent),
    canActivate: [authGuard],
    data: { flow: { flowId: 'workspaces', node: 'workspaces', showInNavbar: true, label: 'Workspaces', scope: 'all', edgesTo: ['workspace-editor'] } },
  },
  {
    path: 'workspaces/:id',
    loadComponent: () =>
      import('./features/workspaces/workspace-editor.component').then((m) => m.WorkspaceEditorComponent),
    canActivate: [authGuard],
    data: { flow: { flowId: 'workspace-editor', node: 'workspace-editor', label: 'Editor', edgesTo: ['workspaces'] } },
  },
  {
    path: 'admin/settings',
    loadComponent: () =>
      import('./features/admin/settings.component').then((m) => m.AdminSettingsComponent),
    canActivate: [authGuard],
    data: { flow: { flowId: 'admin-settings', node: 'admin-settings', showInNavbar: true, label: 'Settings', scope: 'admin', edgesTo: ['workspaces'] } },
  },
  { path: '**', redirectTo: 'workspaces' },
] satisfies FlowRoute[]) as Routes;
